((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There will circulate among them young boys made eternal', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'With vessels, pitchers and a cup [of wine] from a flowing spring -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No headache will they have therefrom, nor will they be intoxicated -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And fruit of what they select', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the meat of fowl, from whatever they desire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [for them are] fair women with large, [beautiful] eyes,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The likenesses of pearls well-protected,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As reward for what they used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will not hear therein ill speech or commission of sin -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Only a saying: "Peace, peace."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The companions of the right - what are the companions of the right?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[They will be] among lote trees with thorns removed', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [banana] trees layered [with fruit]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And shade extended', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And water poured out', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And fruit, abundant [and varied],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Neither limited [to season] nor forbidden,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [upon] beds raised high.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have produced the women of Paradise in a [new] creation', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And made them virgins,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Devoted [to their husbands] and of equal age,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For the companions of the right [who are]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A company of the former peoples', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And a company of the later peoples.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the companions of the left - what are the companions of the left?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[They will be] in scorching fire and scalding water', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And a shade of black smoke,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Neither cool nor beneficial.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed they were, before that, indulging in affluence,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they used to persist in the great violation,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they used to say, "When we die and become dust and bones, are we indeed to be resurrected?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And our forefathers [as well]?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "Indeed, the former and the later peoples', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Are to be gathered together for the appointment of a known Day."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then indeed you, O those astray [who are] deniers,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Will be eating from trees of zaqqum', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And filling with it your bellies', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And drinking on top of it from scalding water', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And will drink as the drinking of thirsty camels.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is their accommodation on the Day of Recompense.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We have created you, so why do you not believe?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you seen that which you emit?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is it you who creates it, or are We the Creator?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We have decreed death among you, and We are not to be outdone', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'In that We will change your likenesses and produce you in that [form] which you do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you have already known the first creation, so will you not remember?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And have you seen that [seed] which you sow?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is it you who makes it grow, or are We the grower?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If We willed, We could make it [dry] debris, and you would remain in wonder,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Saying], "Indeed, we are [now] in debt;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Rather, we have been deprived."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And have you seen the water that you drink?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is it you who brought it down from the clouds, or is it We who bring it down?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If We willed, We could make it bitter, so why are you not grateful?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And have you seen the fire that you ignite?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is it you who produced its tree, or are We the producer?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We have made it a reminder and provision for the travelers,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So exalt the name of your Lord, the Most Great.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then I swear by the setting of the stars,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, it is an oath - if you could know - [most] great.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, it is a noble Qur''an', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'In a Register well-protected;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'None touch it except the purified.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It is] a revelation from the Lord of the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then is it to this statement that you are indifferent', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And make [the thanks for] your provision that you deny [the Provider]?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then why, when the soul at death reaches the throat', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you are at that time looking on -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Our angels are nearer to him than you, but you do not see -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then why do you not, if you are not to be recompensed,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Bring it back, if you should be truthful?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if the deceased was of those brought near to Allah,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then [for him is] rest and bounty and a garden of pleasure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if he was of the companions of the right,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then [the angels will say], "Peace for you; [you are] from the companions of the right."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if he was of the deniers [who were] astray,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then [for him is] accommodation of scalding water', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And burning in Hellfire', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, this is the true certainty,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 56 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So exalt the name of your Lord, the Most Great.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whatever is in the heavens and earth exalts Allah, and He is the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'His is the dominion of the heavens and earth. He gives life and causes death, and He is over all things competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He is the First and the Last, the Ascendant and the Intimate, and He is, of all things, Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who created the heavens and earth in six days and then established Himself above the Throne. He knows what penetrates into the earth and what emerges from it and what descends from the heaven and what ascends therein; and He is with you wherever you are. And Allah, of what you do, is Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'His is the dominion of the heavens and earth. And to Allah are returned [all] matters.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He causes the night to enter the day and causes the day to enter the night, and he is Knowing of that within the breasts.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Believe in Allah and His Messenger and spend out of that in which He has made you successors. For those who have believed among you and spent, there will be a great reward.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And why do you not believe in Allah while the Messenger invites you to believe in your Lord and He has taken your covenant, if you should [truly] be believers?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who sends down upon His Servant [Muhammad] verses of clear evidence that He may bring you out from darknesses into the light. And indeed, Allah is to you Kind and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And why do you not spend in the cause of Allah while to Allah belongs the heritage of the heavens and the earth? Not equal among you are those who spent before the conquest [of Makkah] and fought [and those who did so after it]. Those are greater in degree than they who spent afterwards and fought. But to all Allah has promised the best [reward]. And Allah, with what you do, is Acquainted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who is it that would loan Allah a goodly loan so He will multiply it for him and he will have a noble reward?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On the Day you see the believing men and believing women, their light proceeding before them and on their right, [it will be said], "Your good tidings today are [of] gardens beneath which rivers flow, wherein you will abide eternally." That is what is the great attainment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On the [same] Day the hypocrite men and hypocrite women will say to those who believed, "Wait for us that we may acquire some of your light." It will be said, "Go back behind you and seek light." And a wall will be placed between them with a door, its interior containing mercy, but on the outside of it is torment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The hypocrites will call to the believers, "Were we not with you?" They will say, "Yes, but you afflicted yourselves and awaited [misfortune for us] and doubted, and wishful thinking deluded you until there came the command of Allah. And the Deceiver deceived you concerning Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So today no ransom will be taken from you or from those who disbelieved. Your refuge is the Fire. It is most worthy of you, and wretched is the destination.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Has the time not come for those who have believed that their hearts should become humbly submissive at the remembrance of Allah and what has come down of the truth? And let them not be like those who were given the Scripture before, and a long period passed over them, so their hearts hardened; and many of them are defiantly disobedient.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Know that Allah gives life to the earth after its lifelessness. We have made clear to you the signs; perhaps you will understand.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the men who practice charity and the women who practice charity and [they who] have loaned Allah a goodly loan - it will be multiplied for them, and they will have a noble reward.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who have believed in Allah and His messengers - those are [in the ranks of] the supporters of truth and the martyrs, with their Lord. For them is their reward and their light. But those who have disbelieved and denied Our verses - those are the companions of Hellfire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Know that the life of this world is but amusement and diversion and adornment and boasting to one another and competition in increase of wealth and children - like the example of a rain whose [resulting] plant growth pleases the tillers; then it dries and you see it turned yellow; then it becomes [scattered] debris. And in the Hereafter is severe punishment and forgiveness from Allah and approval. And what is the worldly life except the enjoyment of delusion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Race toward forgiveness from your Lord and a Garden whose width is like the width of the heavens and earth, prepared for those who believed in Allah and His messengers. That is the bounty of Allah which He gives to whom He wills, and Allah is the possessor of great bounty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No disaster strikes upon the earth or among yourselves except that it is in a register before We bring it into being - indeed that, for Allah, is easy -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'In order that you not despair over what has eluded you and not exult [in pride] over what He has given you. And Allah does not like everyone self-deluded and boastful -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Those] who are stingy and enjoin upon people stinginess. And whoever turns away - then indeed, Allah is the Free of need, the Praiseworthy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We have already sent Our messengers with clear evidences and sent down with them the Scripture and the balance that the people may maintain [their affairs] in justice. And We sent down iron, wherein is great military might and benefits for the people, and so that Allah may make evident those who support Him and His messengers unseen. Indeed, Allah is Powerful and Exalted in Might.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have already sent Noah and Abraham and placed in their descendants prophethood and scripture; and among them is he who is guided, but many of them are defiantly disobedient.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We sent following their footsteps Our messengers and followed [them] with Jesus, the son of Mary, and gave him the Gospel. And We placed in the hearts of those who followed him compassion and mercy and monasticism, which they innovated; We did not prescribe it for them except [that they did so] seeking the approval of Allah. But they did not observe it with due observance. So We gave the ones who believed among them their reward, but many of them are defiantly disobedient.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, fear Allah and believe in His Messenger; He will [then] give you a double portion of His mercy and make for you a light by which you will walk and forgive you; and Allah is Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 57 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[This is] so that the People of the Scripture may know that they are not able [to obtain] anything from the bounty of Allah and that [all] bounty is in the hand of Allah; He gives it to whom He wills. And Allah is the possessor of great bounty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Certainly has Allah heard the speech of the one who argues with you, [O Muhammad], concerning her husband and directs her complaint to Allah. And Allah hears your dialogue; indeed, Allah is Hearing and Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who pronounce thihar among you [to separate] from their wives - they are not [consequently] their mothers. Their mothers are none but those who gave birth to them. And indeed, they are saying an objectionable statement and a falsehood. But indeed, Allah is Pardoning and Forgiving.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who pronounce thihar from their wives and then [wish to] go back on what they said - then [there must be] the freeing of a slave before they touch one another. That is what you are admonished thereby; and Allah is Acquainted with what you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he who does not find [a slave] - then a fast for two months consecutively before they touch one another; and he who is unable - then the feeding of sixty poor persons. That is for you to believe [completely] in Allah and His Messenger; and those are the limits [set by] Allah. And for the disbelievers is a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who oppose Allah and His Messenger are abased as those before them were abased. And We have certainly sent down verses of clear evidence. And for the disbelievers is a humiliating punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On the Day when Allah will resurrect them all and inform them of what they did. Allah had enumerated it, while they forgot it; and Allah is, over all things, Witness.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you not considered that Allah knows what is in the heavens and what is on the earth? There is in no private conversation three but that He is the fourth of them, nor are there five but that He is the sixth of them - and no less than that and no more except that He is with them [in knowledge] wherever they are. Then He will inform them of what they did, on the Day of Resurrection. Indeed Allah is, of all things, Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you not considered those who were forbidden from private conversation, then they return to that which they were forbidden and converse among themselves about sin and aggression and disobedience to the Messenger? And when they come to you, they greet you with that [word] by which Allah does not greet you and say among themselves, "Why does Allah not punish us for what we say?" Sufficient for them is Hell, which they will [enter to] burn, and wretched is the destination.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, when you converse privately, do not converse about sin and aggression and disobedience to the Messenger but converse about righteousness and piety. And fear Allah, to whom you will be gathered.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Private conversation is only from Satan that he may grieve those who have believed, but he will not harm them at all except by permission of Allah. And upon Allah let the believers rely.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, when you are told, "Space yourselves" in assemblies, then make space; Allah will make space for you. And when you are told, "Arise," then arise; Allah will raise those who have believed among you and those who were given knowledge, by degrees. And Allah is Acquainted with what you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, when you [wish to] privately consult the Messenger, present before your consultation a charity. That is better for you and purer. But if you find not [the means] - then indeed, Allah is Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you feared to present before your consultation charities? Then when you do not and Allah has forgiven you, then [at least] establish prayer and give zakah and obey Allah and His Messenger. And Allah is Acquainted with what you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you not considered those who make allies of a people with whom Allah has become angry? They are neither of you nor of them, and they swear to untruth while they know [they are lying].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah has prepared for them a severe punishment. Indeed, it was evil that they were doing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They took their [false] oaths as a cover, so they averted [people] from the way of Allah, and for them is a humiliating punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Never will their wealth or their children avail them against Allah at all. Those are the companions of the Fire; they will abide therein eternally', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On the Day Allah will resurrect them all, and they will swear to Him as they swear to you and think that they are [standing] on something. Unquestionably, it is they who are the liars.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Satan has overcome them and made them forget the remembrance of Allah. Those are the party of Satan. Unquestionably, the party of Satan - they will be the losers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the ones who oppose Allah and His Messenger - those will be among the most humbled.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah has written, "I will surely overcome, I and My messengers." Indeed, Allah is Powerful and Exalted in Might.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 58 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You will not find a people who believe in Allah and the Last Day having affection for those who oppose Allah and His Messenger, even if they were their fathers or their sons or their brothers or their kindred. Those - He has decreed within their hearts faith and supported them with spirit from Him. And We will admit them to gardens beneath which rivers flow, wherein they abide eternally. Allah is pleased with them, and they are pleased with Him - those are the party of Allah. Unquestionably, the party of Allah - they are the successful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whatever is in the heavens and whatever is on the earth exalts Allah, and He is the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who expelled the ones who disbelieved among the People of the Scripture from their homes at the first gathering. You did not think they would leave, and they thought that their fortresses would protect them from Allah; but [the decree of] Allah came upon them from where they had not expected, and He cast terror into their hearts [so] they destroyed their houses by their [own] hands and the hands of the believers. So take warning, O people of vision.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if not that Allah had decreed for them evacuation, He would have punished them in [this] world, and for them in the Hereafter is the punishment of the Fire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is because they opposed Allah and His Messenger. And whoever opposes Allah - then indeed, Allah is severe in penalty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whatever you have cut down of [their] palm trees or left standing on their trunks - it was by permission of Allah and so He would disgrace the defiantly disobedient.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what Allah restored [of property] to His Messenger from them - you did not spur for it [in an expedition] any horses or camels, but Allah gives His messengers power over whom He wills, and Allah is over all things competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what Allah restored to His Messenger from the people of the towns - it is for Allah and for the Messenger and for [his] near relatives and orphans and the [stranded] traveler - so that it will not be a perpetual distribution among the rich from among you. And whatever the Messenger has given you - take; and what he has forbidden you - refrain from. And fear Allah; indeed, Allah is severe in penalty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For the poor emigrants who were expelled from their homes and their properties, seeking bounty from Allah and [His] approval and supporting Allah and His Messenger, [there is also a share]. Those are the truthful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [also for] those who were settled in al-Madinah and [adopted] the faith before them. They love those who emigrated to them and find not any want in their breasts of what the emigrants were given but give [them] preference over themselves, even though they are in privation. And whoever is protected from the stinginess of his soul - it is those who will be the successful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [there is a share for] those who came after them, saying, "Our Lord, forgive us and our brothers who preceded us in faith and put not in our hearts [any] resentment toward those who have believed. Our Lord, indeed You are Kind and Merciful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you not considered those who practice hypocrisy, saying to their brothers who have disbelieved among the People of the Scripture, "If you are expelled, we will surely leave with you, and we will not obey, in regard to you, anyone - ever; and if you are fought, we will surely aid you." But Allah testifies that they are liars.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If they are expelled, they will not leave with them, and if they are fought, they will not aid them. And [even] if they should aid them, they will surely turn their backs; then [thereafter] they will not be aided.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You [believers] are more fearful within their breasts than Allah. That is because they are a people who do not understand.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will not fight you all except within fortified cities or from behind walls. Their violence among themselves is severe. You think they are together, but their hearts are diverse. That is because they are a people who do not reason.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Theirs is] like the example of those shortly before them: they tasted the bad consequence of their affair, and they will have a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[The hypocrites are] like the example of Satan when he says to man, "Disbelieve." But when he disbelieves, he says, "Indeed, I am disassociated from you. Indeed, I fear Allah, Lord of the worlds."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So the outcome for both of them is that they will be in the Fire, abiding eternally therein. And that is the recompense of the wrong-doers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, fear Allah. And let every soul look to what it has put forth for tomorrow - and fear Allah. Indeed, Allah is Acquainted with what you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And be not like those who forgot Allah, so He made them forget themselves. Those are the defiantly disobedient.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Not equal are the companions of the Fire and the companions of Paradise. The companions of Paradise - they are the attainers [of success].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If We had sent down this Qur''an upon a mountain, you would have seen it humbled and coming apart from fear of Allah. And these examples We present to the people that perhaps they will give thought.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He is Allah, other than whom there is no deity, Knower of the unseen and the witnessed. He is the Entirely Merciful, the Especially Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He is Allah, other than whom there is no deity, the Sovereign, the Pure, the Perfection, the Bestower of Faith, the Overseer, the Exalted in Might, the Compeller, the Superior. Exalted is Allah above whatever they associate with Him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 59 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He is Allah, the Creator, the Inventor, the Fashioner; to Him belong the best names. Whatever is in the heavens and earth is exalting Him. And He is the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, do not take My enemies and your enemies as allies, extending to them affection while they have disbelieved in what came to you of the truth, having driven out the Prophet and yourselves [only] because you believe in Allah, your Lord. If you have come out for jihad in My cause and seeking means to My approval, [take them not as friends]. You confide to them affection, but I am most knowing of what you have concealed and what you have declared. And whoever does it among you has certainly strayed from the soundness of the way.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If they gain dominance over you, they would be to you as enemies and extend against you their hands and their tongues with evil, and they wish you would disbelieve.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Never will your relatives or your children benefit you; the Day of Resurrection He will judge between you. And Allah, of what you do, is Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There has already been for you an excellent pattern in Abraham and those with him, when they said to their people, "Indeed, we are disassociated from you and from whatever you worship other than Allah. We have denied you, and there has appeared between us and you animosity and hatred forever until you believe in Allah alone" except for the saying of Abraham to his father, "I will surely ask forgiveness for you, but I have not [power to do] for you anything against Allah. Our Lord, upon You we have relied, and to You we have returned, and to You is the destination.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Our Lord, make us not [objects of] torment for the disbelievers and forgive us, our Lord. Indeed, it is You who is the Exalted in Might, the Wise."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There has certainly been for you in them an excellent pattern for anyone whose hope is in Allah and the Last Day. And whoever turns away - then indeed, Allah is the Free of need, the Praiseworthy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Perhaps Allah will put, between you and those to whom you have been enemies among them, affection. And Allah is competent, and Allah is Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah does not forbid you from those who do not fight you because of religion and do not expel you from your homes - from being righteous toward them and acting justly toward them. Indeed, Allah loves those who act justly.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah only forbids you from those who fight you because of religion and expel you from your homes and aid in your expulsion - [forbids] that you make allies of them. And whoever makes allies of them, then it is those who are the wrongdoers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, when the believing women come to you as emigrants, examine them. Allah is most knowing as to their faith. And if you know them to be believers, then do not return them to the disbelievers; they are not lawful [wives] for them, nor are they lawful [husbands] for them. But give the disbelievers what they have spent. And there is no blame upon you if you marry them when you have given them their due compensation. And hold not to marriage bonds with disbelieving women, but ask for what you have spent and let them ask for what they have spent. That is the judgement of Allah; He judges between you. And Allah is Knowing and Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if you have lost any of your wives to the disbelievers and you subsequently obtain [something], then give those whose wives have gone the equivalent of what they had spent. And fear Allah, in whom you are believers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O Prophet, when the believing women come to you pledging to you that they will not associate anything with Allah, nor will they steal, nor will they commit unlawful sexual intercourse, nor will they kill their children, nor will they bring forth a slander they have invented between their arms and legs, nor will they disobey you in what is right - then accept their pledge and ask forgiveness for them of Allah. Indeed, Allah is Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 60 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, do not make allies of a people with whom Allah has become angry. They have despaired of [reward in] the Hereafter just as the disbelievers have despaired of [meeting] the inhabitants of the graves.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whatever is in the heavens and whatever is on the earth exalts Allah, and He is the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, why do you say what you do not do?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Great is hatred in the sight of Allah that you say what you do not do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Allah loves those who fight in His cause in a row as though they are a [single] structure joined firmly.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention, O Muhammad], when Moses said to his people, "O my people, why do you harm me while you certainly know that I am the messenger of Allah to you?" And when they deviated, Allah caused their hearts to deviate. And Allah does not guide the defiantly disobedient people.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention] when Jesus, the son of Mary, said, "O children of Israel, indeed I am the messenger of Allah to you confirming what came before me of the Torah and bringing good tidings of a messenger to come after me, whose name is Ahmad." But when he came to them with clear evidences, they said, "This is obvious magic."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And who is more unjust than one who invents about Allah untruth while he is being invited to Islam. And Allah does not guide the wrongdoing people.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They want to extinguish the light of Allah with their mouths, but Allah will perfect His light, although the disbelievers dislike it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who sent His Messenger with guidance and the religion of truth to manifest it over all religion, although those who associate others with Allah dislike it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, shall I guide you to a transaction that will save you from a painful punishment?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It is that] you believe in Allah and His Messenger and strive in the cause of Allah with your wealth and your lives. That is best for you, if you should know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He will forgive for you your sins and admit you to gardens beneath which rivers flow and pleasant dwellings in gardens of perpetual residence. That is the great attainment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [you will obtain] another [favor] that you love - victory from Allah and an imminent conquest; and give good tidings to the believers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 61 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, be supporters of Allah, as when Jesus, the son of Mary, said to the disciples, "Who are my supporters for Allah?" The disciples said, "We are supporters of Allah." And a faction of the Children of Israel believed and a faction disbelieved. So We supported those who believed against their enemy, and they became dominant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 62 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whatever is in the heavens and whatever is on the earth is exalting Allah, the Sovereign, the Pure, the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 62 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who has sent among the unlettered a Messenger from themselves reciting to them His verses and purifying them and teaching them the Book and wisdom - although they were before in clear error -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 62 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [to] others of them who have not yet joined them. And He is the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 62 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is the bounty of Allah, which He gives to whom He wills, and Allah is the possessor of great bounty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 62 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The example of those who were entrusted with the Torah and then did not take it on is like that of a donkey who carries volumes [of books]. Wretched is the example of the people who deny the signs of Allah. And Allah does not guide the wrongdoing people.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 62 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "O you who are Jews, if you claim that you are allies of Allah, excluding the [other] people, then wish for death, if you should be truthful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 62 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they will not wish for it, ever, because of what their hands have put forth. And Allah is Knowing of the wrongdoers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 62 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Indeed, the death from which you flee - indeed, it will meet you. Then you will be returned to the Knower of the unseen and the witnessed, and He will inform you about what you used to do."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 62 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, when [the adhan] is called for the prayer on the day of Jumu''ah [Friday], then proceed to the remembrance of Allah and leave trade. That is better for you, if you only knew.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 62 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the prayer has been concluded, disperse within the land and seek from the bounty of Allah, and remember Allah often that you may succeed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 62 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when they saw a transaction or a diversion, [O Muhammad], they rushed to it and left you standing. Say, "What is with Allah is better than diversion and than a transaction, and Allah is the best of providers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 63 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When the hypocrites come to you, [O Muhammad], they say, "We testify that you are the Messenger of Allah." And Allah knows that you are His Messenger, and Allah testifies that the hypocrites are liars.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 63 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They have taken their oaths as a cover, so they averted [people] from the way of Allah. Indeed, it was evil that they were doing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 63 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is because they believed, and then they disbelieved; so their hearts were sealed over, and they do not understand.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 63 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when you see them, their forms please you, and if they speak, you listen to their speech. [They are] as if they were pieces of wood propped up - they think that every shout is against them. They are the enemy, so beware of them. May Allah destroy them; how are they deluded?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 63 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when it is said to them, "Come, the Messenger of Allah will ask forgiveness for you," they turn their heads aside and you see them evading while they are arrogant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 63 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is all the same for them whether you ask forgiveness for them or do not ask forgiveness for them; never will Allah forgive them. Indeed, Allah does not guide the defiantly disobedient people.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 63 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They are the ones who say, "Do not spend on those who are with the Messenger of Allah until they disband." And to Allah belongs the depositories of the heavens and the earth, but the hypocrites do not understand.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 63 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They say, "If we return to al-Madinah, the more honored [for power] will surely expel therefrom the more humble." And to Allah belongs [all] honor, and to His Messenger, and to the believers, but the hypocrites do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 63 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, let not your wealth and your children divert you from remembrance of Allah. And whoever does that - then those are the losers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 63 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And spend [in the way of Allah] from what We have provided you before death approaches one of you and he says, "My Lord, if only You would delay me for a brief term so I would give charity and be among the righteous."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 63 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But never will Allah delay a soul when its time has come. And Allah is Acquainted with what you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whatever is in the heavens and whatever is on the earth is exalting Allah. To Him belongs dominion, and to Him belongs [all] praise, and He is over all things competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who created you, and among you is the disbeliever, and among you is the believer. And Allah, of what you do, is Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He created the heavens and earth in truth and formed you and perfected your forms; and to Him is the [final] destination.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He knows what is within the heavens and earth and knows what you conceal and what you declare. And Allah is Knowing of that within the breasts.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Has there not come to you the news of those who disbelieved before? So they tasted the bad consequence of their affair, and they will have a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is because their messengers used to come to them with clear evidences, but they said, "Shall human beings guide us?" and disbelieved and turned away. And Allah dispensed [with them]; and Allah is Free of need and Praiseworthy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who disbelieve have claimed that they will never be resurrected. Say, "Yes, by my Lord, you will surely be resurrected; then you will surely be informed of what you did. And that, for Allah, is easy."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So believe in Allah and His Messenger and the Qur''an which We have sent down. And Allah is Acquainted with what you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Day He will assemble you for the Day of Assembly - that is the Day of Deprivation. And whoever believes in Allah and does righteousness - He will remove from him his misdeeds and admit him to gardens beneath which rivers flow, wherein they will abide forever. That is the great attainment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But the ones who disbelieved and denied Our verses - those are the companions of the Fire, abiding eternally therein; and wretched is the destination.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No disaster strikes except by permission of Allah. And whoever believes in Allah - He will guide his heart. And Allah is Knowing of all things.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And obey Allah and obey the Messenger; but if you turn away - then upon Our Messenger is only [the duty of] clear notification.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah - there is no deity except Him. And upon Allah let the believers rely.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, indeed, among your wives and your children are enemies to you, so beware of them. But if you pardon and overlook and forgive - then indeed, Allah is Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Your wealth and your children are but a trial, and Allah has with Him a great reward.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So fear Allah as much as you are able and listen and obey and spend [in the way of Allah]; it is better for your selves. And whoever is protected from the stinginess of his soul - it is those who will be the successful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If you loan Allah a goodly loan, He will multiply it for you and forgive you. And Allah is Most Appreciative and Forbearing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 64 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Knower of the unseen and the witnessed, the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 65 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O Prophet, when you [Muslims] divorce women, divorce them for [the commencement of] their waiting period and keep count of the waiting period, and fear Allah, your Lord. Do not turn them out of their [husbands''] houses, nor should they [themselves] leave [during that period] unless they are committing a clear immorality. And those are the limits [set by] Allah. And whoever transgresses the limits of Allah has certainly wronged himself. You know not; perhaps Allah will bring about after that a [different] matter.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 65 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they have [nearly] fulfilled their term, either retain them according to acceptable terms or part with them according to acceptable terms. And bring to witness two just men from among you and establish the testimony for [the acceptance of] Allah. That is instructed to whoever should believe in Allah and the Last day. And whoever fears Allah - He will make for him a way out', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 65 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And will provide for him from where he does not expect. And whoever relies upon Allah - then He is sufficient for him. Indeed, Allah will accomplish His purpose. Allah has already set for everything a [decreed] extent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 65 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who no longer expect menstruation among your women - if you doubt, then their period is three months, and [also for] those who have not menstruated. And for those who are pregnant, their term is until they give birth. And whoever fears Allah - He will make for him of his matter ease.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 65 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is the command of Allah, which He has sent down to you; and whoever fears Allah - He will remove for him his misdeeds and make great for him his reward.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 65 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Lodge them [in a section] of where you dwell out of your means and do not harm them in order to oppress them. And if they should be pregnant, then spend on them until they give birth. And if they breastfeed for you, then give them their payment and confer among yourselves in the acceptable way; but if you are in discord, then there may breastfeed for the father another woman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 65 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Let a man of wealth spend from his wealth, and he whose provision is restricted - let him spend from what Allah has given him. Allah does not charge a soul except [according to] what He has given it. Allah will bring about, after hardship, ease.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 65 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And how many a city was insolent toward the command of its Lord and His messengers, so We took it to severe account and punished it with a terrible punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 65 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it tasted the bad consequence of its affair, and the outcome of its affair was loss.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 65 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah has prepared for them a severe punishment; so fear Allah, O you of understanding who have believed. Allah has sent down to you the Qur''an.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 65 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[He sent] a Messenger [Muhammad] reciting to you the distinct verses of Allah that He may bring out those who believe and do righteous deeds from darknesses into the light. And whoever believes in Allah and does righteousness - He will admit him into gardens beneath which rivers flow to abide therein forever. Allah will have perfected for him a provision.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 65 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is Allah who has created seven heavens and of the earth, the like of them. [His] command descends among them so you may know that Allah is over all things competent and that Allah has encompassed all things in knowledge.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 66 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O Prophet, why do you prohibit [yourself from] what Allah has made lawful for you, seeking the approval of your wives? And Allah is Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 66 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah has already ordained for you [Muslims] the dissolution of your oaths. And Allah is your protector, and He is the Knowing, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 66 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [remember] when the Prophet confided to one of his wives a statement; and when she informed [another] of it and Allah showed it to him, he made known part of it and ignored a part. And when he informed her about it, she said, "Who told you this?" He said, "I was informed by the Knowing, the Acquainted."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 66 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If you two [wives] repent to Allah, [it is best], for your hearts have deviated. But if you cooperate against him - then indeed Allah is his protector, and Gabriel and the righteous of the believers and the angels, moreover, are [his] assistants.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 66 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Perhaps his Lord, if he divorced you [all], would substitute for him wives better than you - submitting [to Allah], believing, devoutly obedient, repentant, worshipping, and traveling - [ones] previously married and virgins.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 66 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, protect yourselves and your families from a Fire whose fuel is people and stones, over which are [appointed] angels, harsh and severe; they do not disobey Allah in what He commands them but do what they are commanded.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 66 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have disbelieved, make no excuses that Day. You will only be recompensed for what you used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 66 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, repent to Allah with sincere repentance. Perhaps your Lord will remove from you your misdeeds and admit you into gardens beneath which rivers flow [on] the Day when Allah will not disgrace the Prophet and those who believed with him. Their light will proceed before them and on their right; they will say, "Our Lord, perfect for us our light and forgive us. Indeed, You are over all things competent."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 66 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O Prophet, strive against the disbelievers and the hypocrites and be harsh upon them. And their refuge is Hell, and wretched is the destination.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 66 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah presents an example of those who disbelieved: the wife of Noah and the wife of Lot. They were under two of Our righteous servants but betrayed them, so those prophets did not avail them from Allah at all, and it was said, "Enter the Fire with those who enter."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 66 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah presents an example of those who believed: the wife of Pharaoh, when she said, "My Lord, build for me near You a house in Paradise and save me from Pharaoh and his deeds and save me from the wrongdoing people."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 66 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [the example of] Mary, the daughter of ''Imran, who guarded her chastity, so We blew into [her garment] through Our angel, and she believed in the words of her Lord and His scriptures and was of the devoutly obedient.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Blessed is He in whose hand is dominion, and He is over all things competent -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[He] who created death and life to test you [as to] which of you is best in deed - and He is the Exalted in Might, the Forgiving -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[And] who created seven heavens in layers. You do not see in the creation of the Most Merciful any inconsistency. So return [your] vision [to the sky]; do you see any breaks?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then return [your] vision twice again. [Your] vision will return to you humbled while it is fatigued.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have certainly beautified the nearest heaven with stars and have made [from] them what is thrown at the devils and have prepared for them the punishment of the Blaze.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And for those who disbelieved in their Lord is the punishment of Hell, and wretched is the destination.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When they are thrown into it, they hear from it a [dreadful] inhaling while it boils up.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It almost bursts with rage. Every time a company is thrown into it, its keepers ask them, "Did there not come to you a warner?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will say," Yes, a warner had come to us, but we denied and said, ''Allah has not sent down anything. You are not but in great error.''"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will say, "If only we had been listening or reasoning, we would not be among the companions of the Blaze."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will admit their sin, so [it is] alienation for the companions of the Blaze.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who fear their Lord unseen will have forgiveness and great reward.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And conceal your speech or publicize it; indeed, He is Knowing of that within the breasts.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Does He who created not know, while He is the Subtle, the Acquainted?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who made the earth tame for you - so walk among its slopes and eat of His provision - and to Him is the resurrection.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do you feel secure that He who [holds authority] in the heaven would not cause the earth to swallow you and suddenly it would sway?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do you feel secure that He who [holds authority] in the heaven would not send against you a storm of stones? Then you would know how [severe] was My warning.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And already had those before them denied, and how [terrible] was My reproach.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do they not see the birds above them with wings outspread and [sometimes] folded in? None holds them [aloft] except the Most Merciful. Indeed He is, of all things, Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or who is it that could be an army for you to aid you other than the Most Merciful? The disbelievers are not but in delusion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or who is it that could provide for you if He withheld His provision? But they have persisted in insolence and aversion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then is one who walks fallen on his face better guided or one who walks erect on a straight path?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "It is He who has produced you and made for you hearing and vision and hearts; little are you grateful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "It is He who has multiplied you throughout the earth, and to Him you will be gathered."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "When is this promise, if you should be truthful?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "The knowledge is only with Allah, and I am only a clear warner."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when they see it approaching, the faces of those who disbelieve will be distressed, and it will be said, "This is that for which you used to call."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "Have you considered: whether Allah should cause my death and those with me or have mercy upon us, who can protect the disbelievers from a painful punishment?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "He is the Most Merciful; we have believed in Him, and upon Him we have relied. And you will [come to] know who it is that is in clear error."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 67 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Have you considered: if your water was to become sunken [into the earth], then who could bring you flowing water?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nun. By the pen and what they inscribe,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You are not, [O Muhammad], by the favor of your Lord, a madman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, for you is a reward uninterrupted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, you are of a great moral character.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So you will see and they will see', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Which of you is the afflicted [by a devil].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, your Lord is most knowing of who has gone astray from His way, and He is most knowing of the [rightly] guided.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then do not obey the deniers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They wish that you would soften [in your position], so they would soften [toward you].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not obey every worthless habitual swearer', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[And] scorner, going about with malicious gossip -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A preventer of good, transgressing and sinful,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Cruel, moreover, and an illegitimate pretender.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Because he is a possessor of wealth and children,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When Our verses are recited to him, he says, "Legends of the former peoples."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We will brand him upon the snout.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have tried them as We tried the companions of the garden, when they swore to cut its fruit in the [early] morning', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Without making exception.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So there came upon the garden an affliction from your Lord while they were asleep.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it became as though reaped.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they called one another at morning,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Saying], "Go early to your crop if you would cut the fruit."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So they set out, while lowering their voices,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Saying], "There will surely not enter it today upon you [any] poor person."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they went early in determination, [assuming themselves] able.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when they saw it, they said, "Indeed, we are lost;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Rather, we have been deprived."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The most moderate of them said, "Did I not say to you, ''Why do you not exalt [Allah]?'' "', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "Exalted is our Lord! Indeed, we were wrongdoers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then they approached one another, blaming each other.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "O woe to us; indeed we were transgressors.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Perhaps our Lord will substitute for us [one] better than it. Indeed, we are toward our Lord desirous."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Such is the punishment [of this world]. And the punishment of the Hereafter is greater, if they only knew.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, for the righteous with their Lord are the Gardens of Pleasure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then will We treat the Muslims like the criminals?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'What is [the matter] with you? How do you judge?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do you have a scripture in which you learn', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That indeed for you is whatever you choose?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do you have oaths [binding] upon Us, extending until the Day of Resurrection, that indeed for you is whatever you judge?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Ask them which of them, for that [claim], is responsible.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do they have partners? Then let them bring their partners, if they should be truthful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Day the shin will be uncovered and they are invited to prostration but the disbelievers will not be able,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Their eyes humbled, humiliation will cover them. And they used to be invited to prostration while they were sound.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So leave Me, [O Muhammad], with [the matter of] whoever denies the Qur''an. We will progressively lead them [to punishment] from where they do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And I will give them time. Indeed, My plan is firm.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do you ask of them a payment, so they are by debt burdened down?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or have they [knowledge of] the unseen, so they write [it] down?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then be patient for the decision of your Lord, [O Muhammad], and be not like the companion of the fish when he called out while he was distressed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If not that a favor from his Lord overtook him, he would have been thrown onto the naked shore while he was censured.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And his Lord chose him and made him of the righteous.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, those who disbelieve would almost make you slip with their eyes when they hear the message, and they say, "Indeed, he is mad."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 68 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But it is not except a reminder to the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Inevitable Reality -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'What is the Inevitable Reality?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what can make you know what is the Inevitable Reality?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Thamud and ''Aad denied the Striking Calamity.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So as for Thamud, they were destroyed by the overpowering [blast].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And as for ''Aad, they were destroyed by a screaming, violent wind', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Which Allah imposed upon them for seven nights and eight days in succession, so you would see the people therein fallen as if they were hollow trunks of palm trees.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then do you see of them any remains?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there came Pharaoh and those before him and the overturned cities with sin.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they disobeyed the messenger of their Lord, so He seized them with a seizure exceeding [in severity].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, when the water overflowed, We carried your ancestors in the sailing ship', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That We might make it for you a reminder and [that] a conscious ear would be conscious of it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then when the Horn is blown with one blast', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the earth and the mountains are lifted and leveled with one blow -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then on that Day, the Resurrection will occur,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the heaven will split [open], for that Day it is infirm.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the angels are at its edges. And there will bear the Throne of your Lord above them, that Day, eight [of them].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That Day, you will be exhibited [for judgement]; not hidden among you is anything concealed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So as for he who is given his record in his right hand, he will say, "Here, read my record!', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, I was certain that I would be meeting my account."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So he will be in a pleasant life -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'In an elevated garden,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Its [fruit] to be picked hanging near.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[They will be told], "Eat and drink in satisfaction for what you put forth in the days past."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for he who is given his record in his left hand, he will say, "Oh, I wish I had not been given my record', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And had not known what is my account.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'I wish my death had been the decisive one.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'My wealth has not availed me.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Gone from me is my authority."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah will say], "Seize him and shackle him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then into Hellfire drive him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then into a chain whose length is seventy cubits insert him."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, he did not used to believe in Allah, the Most Great,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nor did he encourage the feeding of the poor.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So there is not for him here this Day any devoted friend', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nor any food except from the discharge of wounds;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'None will eat it except the sinners.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So I swear by what you see', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what you do not see', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[That] indeed, the Qur''an is the word of a noble Messenger.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is not the word of a poet; little do you believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nor the word of a soothsayer; little do you remember.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It is] a revelation from the Lord of the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if Muhammad had made up about Us some [false] sayings,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We would have seized him by the right hand;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We would have cut from him the aorta.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there is no one of you who could prevent [Us] from him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, the Qur''an is a reminder for the righteous.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, We know that among you are deniers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, it will be [a cause of] regret upon the disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, it is the truth of certainty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 69 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So exalt the name of your Lord, the Most Great.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A supplicant asked for a punishment bound to happen', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To the disbelievers; of it there is no preventer.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It is] from Allah, owner of the ways of ascent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The angels and the Spirit will ascend to Him during a Day the extent of which is fifty thousand years.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So be patient with gracious patience.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, they see it [as] distant,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But We see it [as] near.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On the Day the sky will be like murky oil,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the mountains will be like wool,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And no friend will ask [anything of] a friend,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will be shown each other. The criminal will wish that he could be ransomed from the punishment of that Day by his children', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And his wife and his brother', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And his nearest kindred who shelter him', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whoever is on earth entirely [so] then it could save him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! Indeed, it is the Flame [of Hell],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A remover of exteriors.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It invites he who turned his back [on truth] and went away [from obedience]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And collected [wealth] and hoarded.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, mankind was created anxious:', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When evil touches him, impatient,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when good touches him, withholding [of it],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except the observers of prayer -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who are constant in their prayer', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those within whose wealth is a known right', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For the petitioner and the deprived -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who believe in the Day of Recompense', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who are fearful of the punishment of their Lord -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the punishment of their Lord is not that from which one is safe -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who guard their private parts', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except from their wives or those their right hands possess, for indeed, they are not to be blamed -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But whoever seeks beyond that, then they are the transgressors -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who are to their trusts and promises attentive', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who are in their testimonies upright', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who [carefully] maintain their prayer:', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will be in gardens, honored.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So what is [the matter] with those who disbelieve, hastening [from] before you, [O Muhammad],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[To sit] on [your] right and [your] left in separate groups?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Does every person among them aspire to enter a garden of pleasure?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! Indeed, We have created them from that which they know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So I swear by the Lord of [all] risings and settings that indeed We are able', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To replace them with better than them; and We are not to be outdone.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So leave them to converse vainly and amuse themselves until they meet their Day which they are promised -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Day they will emerge from the graves rapidly as if they were, toward an erected idol, hastening.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 70 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Their eyes humbled, humiliation will cover them. That is the Day which they had been promised.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We sent Noah to his people, [saying], "Warn your people before there comes to them a painful punishment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "O my people, indeed I am to you a clear warner,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Saying], ''Worship Allah, fear Him and obey me.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah will forgive you of your sins and delay you for a specified term. Indeed, the time [set by] Allah, when it comes, will not be delayed, if you only knew.'' "', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "My Lord, indeed I invited my people [to truth] night and day.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But my invitation increased them not except in flight.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, every time I invited them that You may forgive them, they put their fingers in their ears, covered themselves with their garments, persisted, and were arrogant with [great] arrogance.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then I invited them publicly.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then I announced to them and [also] confided to them secretly', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And said, ''Ask forgiveness of your Lord. Indeed, He is ever a Perpetual Forgiver.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He will send [rain from] the sky upon you in [continuing] showers', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And give you increase in wealth and children and provide for you gardens and provide for you rivers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'What is [the matter] with you that you do not attribute to Allah [due] grandeur', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'While He has created you in stages?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do you not consider how Allah has created seven heavens in layers', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And made the moon therein a [reflected] light and made the sun a burning lamp?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah has caused you to grow from the earth a [progressive] growth.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then He will return you into it and extract you [another] extraction.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah has made for you the earth an expanse', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That you may follow therein roads of passage.'' "', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Noah said, "My Lord, indeed they have disobeyed me and followed him whose wealth and children will not increase him except in loss.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they conspired an immense conspiracy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And said, ''Never leave your gods and never leave Wadd or Suwa'' or Yaghuth and Ya''uq and Nasr.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And already they have misled many. And, [my Lord], do not increase the wrongdoers except in error."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Because of their sins they were drowned and put into the Fire, and they found not for themselves besides Allah [any] helpers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Noah said, "My Lord, do not leave upon the earth from among the disbelievers an inhabitant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, if You leave them, they will mislead Your servants and not beget except [every] wicked one and [confirmed] disbeliever.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 71 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'My Lord, forgive me and my parents and whoever enters my house a believer and the believing men and believing women. And do not increase the wrongdoers except in destruction."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "It has been revealed to me that a group of the jinn listened and said, ''Indeed, we have heard an amazing Qur''an.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It guides to the right course, and we have believed in it. And we will never associate with our Lord anyone.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [it teaches] that exalted is the nobleness of our Lord; He has not taken a wife or a son', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And that our foolish one has been saying about Allah an excessive transgression.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And we had thought that mankind and the jinn would never speak about Allah a lie.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there were men from mankind who sought refuge in men from the jinn, so they [only] increased them in burden.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they had thought, as you thought, that Allah would never send anyone [as a messenger].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And we have sought [to reach] the heaven but found it filled with powerful guards and burning flames.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And we used to sit therein in positions for hearing, but whoever listens now will find a burning flame lying in wait for him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And we do not know [therefore] whether evil is intended for those on earth or whether their Lord intends for them a right course.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And among us are the righteous, and among us are [others] not so; we were [of] divided ways.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And we have become certain that we will never cause failure to Allah upon earth, nor can we escape Him by flight.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when we heard the guidance, we believed in it. And whoever believes in his Lord will not fear deprivation or burden.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And among us are Muslims [in submission to Allah], and among us are the unjust. And whoever has become Muslim - those have sought out the right course.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for the unjust, they will be, for Hell, firewood.''', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [Allah revealed] that if they had remained straight on the way, We would have given them abundant provision', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So We might test them therein. And whoever turns away from the remembrance of his Lord He will put into arduous punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [He revealed] that the masjids are for Allah, so do not invoke with Allah anyone.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And that when the Servant of Allah stood up supplicating Him, they almost became about him a compacted mass."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "I only invoke my Lord and do not associate with Him anyone."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Indeed, I do not possess for you [the power of] harm or right direction."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Indeed, there will never protect me from Allah anyone [if I should disobey], nor will I find in other than Him a refuge.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But [I have for you] only notification from Allah, and His messages." And whoever disobeys Allah and His Messenger - then indeed, for him is the fire of Hell; they will abide therein forever.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[The disbelievers continue] until, when they see that which they are promised, then they will know who is weaker in helpers and less in number.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "I do not know if what you are promised is near or if my Lord will grant for it a [long] period."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[He is] Knower of the unseen, and He does not disclose His [knowledge of the] unseen to anyone', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except whom He has approved of messengers, and indeed, He sends before each messenger and behind him observers', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 72 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That he may know that they have conveyed the messages of their Lord; and He has encompassed whatever is with them and has enumerated all things in number.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who wraps himself [in clothing],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Arise [to pray] the night, except for a little -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Half of it - or subtract from it a little', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or add to it, and recite the Qur''an with measured recitation.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We will cast upon you a heavy word.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the hours of the night are more effective for concurrence [of heart and tongue] and more suitable for words.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, for you by day is prolonged occupation.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And remember the name of your Lord and devote yourself to Him with [complete] devotion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[He is] the Lord of the East and the West; there is no deity except Him, so take Him as Disposer of [your] affairs.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And be patient over what they say and avoid them with gracious avoidance.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And leave Me with [the matter of] the deniers, those of ease [in life], and allow them respite a little.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, with Us [for them] are shackles and burning fire', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And food that chokes and a painful punishment -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On the Day the earth and the mountains will convulse and the mountains will become a heap of sand pouring down.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have sent to you a Messenger as a witness upon you just as We sent to Pharaoh a messenger.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But Pharaoh disobeyed the messenger, so We seized him with a ruinous seizure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then how can you fear, if you disbelieve, a Day that will make the children white- haired?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The heaven will break apart therefrom; ever is His promise fulfilled.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, this is a reminder, so whoever wills may take to his Lord a way.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 73 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, your Lord knows, [O Muhammad], that you stand [in prayer] almost two thirds of the night or half of it or a third of it, and [so do] a group of those with you. And Allah determines [the extent of] the night and the day. He has known that you [Muslims] will not be able to do it and has turned to you in forgiveness, so recite what is easy [for you] of the Qur''an. He has known that there will be among you those who are ill and others traveling throughout the land seeking [something] of the bounty of Allah and others fighting for the cause of Allah. So recite what is easy from it and establish prayer and give zakah and loan Allah a goodly loan. And whatever good you put forward for yourselves - you will find it with Allah. It is better and greater in reward. And seek forgiveness of Allah. Indeed, Allah is Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who covers himself [with a garment],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Arise and warn', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And your Lord glorify', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And your clothing purify', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And uncleanliness avoid', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not confer favor to acquire more', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But for your Lord be patient.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the trumpet is blown,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That Day will be a difficult day', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For the disbelievers - not easy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Leave Me with the one I created alone', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to whom I granted extensive wealth', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And children present [with him]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And spread [everything] before him, easing [his life].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then he desires that I should add more.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! Indeed, he has been toward Our verses obstinate.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'I will cover him with arduous torment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, he thought and deliberated.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So may he be destroyed [for] how he deliberated.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then may he be destroyed [for] how he deliberated.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then he considered [again];', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then he frowned and scowled;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then he turned back and was arrogant', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And said, "This is not but magic imitated [from others].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'This is not but the word of a human being."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'I will drive him into Saqar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what can make you know what is Saqar?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It lets nothing remain and leaves nothing [unburned],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Blackening the skins.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Over it are nineteen [angels].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have not made the keepers of the Fire except angels. And We have not made their number except as a trial for those who disbelieve - that those who were given the Scripture will be convinced and those who have believed will increase in faith and those who were given the Scripture and the believers will not doubt and that those in whose hearts is hypocrisy and the disbelievers will say, "What does Allah intend by this as an example?" Thus does Allah leave astray whom He wills and guides whom He wills. And none knows the soldiers of your Lord except Him. And mention of the Fire is not but a reminder to humanity.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! By the moon', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the night when it departs', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the morning when it brightens,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the Fire is of the greatest [afflictions]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As a warning to humanity -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To whoever wills among you to proceed or stay behind.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Every soul, for what it has earned, will be retained', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except the companions of the right,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Who will be] in gardens, questioning each other', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'About the criminals,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[And asking them], "What put you into Saqar?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will say, "We were not of those who prayed,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nor did we used to feed the poor.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And we used to enter into vain discourse with those who engaged [in it],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And we used to deny the Day of Recompense', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Until there came to us the certainty."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So there will not benefit them the intercession of [any] intercessors.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then what is [the matter] with them that they are, from the reminder, turning away', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As if they were alarmed donkeys', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Fleeing from a lion?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Rather, every person among them desires that he would be given scriptures spread about.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! But they do not fear the Hereafter.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! Indeed, the Qur''an is a reminder', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then whoever wills will remember it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 74 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will not remember except that Allah wills. He is worthy of fear and adequate for [granting] forgiveness.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'I swear by the Day of Resurrection', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And I swear by the reproaching soul [to the certainty of resurrection].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Does man think that We will not assemble his bones?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Yes. [We are] Able [even] to proportion his fingertips.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But man desires to continue in sin.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He asks, "When is the Day of Resurrection?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when vision is dazzled', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the moon darkens', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the sun and the moon are joined,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Man will say on that Day, "Where is the [place of] escape?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! There is no refuge.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To your Lord, that Day, is the [place of] permanence.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Man will be informed that Day of what he sent ahead and kept back.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Rather, man, against himself, will be a witness,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Even if he presents his excuses.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Move not your tongue with it, [O Muhammad], to hasten with recitation of the Qur''an.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, upon Us is its collection [in your heart] and [to make possible] its recitation.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when We have recited it [through Gabriel], then follow its recitation.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then upon Us is its clarification [to you].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! But you love the immediate', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And leave the Hereafter.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Some] faces, that Day, will be radiant,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Looking at their Lord.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [some] faces, that Day, will be contorted,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Expecting that there will be done to them [something] backbreaking.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! When the soul has reached the collar bones', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is said, "Who will cure [him]?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the dying one is certain that it is the [time of] separation', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the leg is wound about the leg,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To your Lord, that Day, will be the procession.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the disbeliever had not believed, nor had he prayed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But [instead], he denied and turned away.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And then he went to his people, swaggering [in pride].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Woe to you, and woe!', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then woe to you, and woe!', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Does man think that he will be left neglected?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Had he not been a sperm from semen emitted?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then he was a clinging clot, and [Allah] created [his form] and proportioned [him]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And made of him two mates, the male and the female.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is not that [Creator] Able to give life to the dead?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Has there [not] come upon man a period of time when he was not a thing [even] mentioned?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We created man from a sperm-drop mixture that We may try him; and We made him hearing and seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We guided him to the way, be he grateful or be he ungrateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have prepared for the disbelievers chains and shackles and a blaze.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the righteous will drink from a cup [of wine] whose mixture is of Kafur,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A spring of which the [righteous] servants of Allah will drink; they will make it gush forth in force [and abundance].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They [are those who] fulfill [their] vows and fear a Day whose evil will be widespread.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they give food in spite of love for it to the needy, the orphan, and the captive,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Saying], "We feed you only for the countenance of Allah. We wish not from you reward or gratitude.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We fear from our Lord a Day austere and distressful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So Allah will protect them from the evil of that Day and give them radiance and happiness', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And will reward them for what they patiently endured [with] a garden [in Paradise] and silk [garments].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[They will be] reclining therein on adorned couches. They will not see therein any [burning] sun or [freezing] cold.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And near above them are its shades, and its [fruit] to be picked will be lowered in compliance.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there will be circulated among them vessels of silver and cups having been [created] clear [as glass],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Clear glasses [made] from silver of which they have determined the measure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will be given to drink a cup [of wine] whose mixture is of ginger', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[From] a fountain within Paradise named Salsabeel.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There will circulate among them young boys made eternal. When you see them, you would think them [as beautiful as] scattered pearls.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when you look there [in Paradise], you will see pleasure and great dominion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Upon the inhabitants will be green garments of fine silk and brocade. And they will be adorned with bracelets of silver, and their Lord will give them a purifying drink.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[And it will be said], "Indeed, this is for you a reward, and your effort has been appreciated."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, it is We who have sent down to you, [O Muhammad], the Qur''an progressively.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So be patient for the decision of your Lord and do not obey from among them a sinner or ungrateful [disbeliever].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And mention the name of your Lord [in prayer] morning and evening', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And during the night prostrate to Him and exalt Him a long [part of the] night.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, these [disbelievers] love the immediate and leave behind them a grave Day.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We have created them and strengthened their forms, and when We will, We can change their likenesses with [complete] alteration.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, this is a reminder, so he who wills may take to his Lord a way.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you do not will except that Allah wills. Indeed, Allah is ever Knowing and Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He admits whom He wills into His mercy; but the wrongdoers - He has prepared for them a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 77 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By those [winds] sent forth in gusts', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 77 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the winds that blow violently', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 77 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the winds that spread [clouds]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 77 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those [angels] who bring criterion', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 77 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those [angels] who deliver a message', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 77 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As justification or warning,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 77 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, what you are promised is to occur.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 77 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when the stars are obliterated', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 77 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the heaven is opened', NOW(), NOW()),
