((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Their eyes humbled.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They are [presently] saying, "Will we indeed be returned to [our] former state [of life]?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Even if we should be decayed bones?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They say, "That, then, would be a losing return."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, it will be but one shout,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And suddenly they will be [alert] upon the earth''s surface.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Has there reached you the story of Moses? -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When his Lord called to him in the sacred valley of Tuwa,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '"Go to Pharaoh. Indeed, he has transgressed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And say to him, ''Would you [be willing to] purify yourself', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And let me guide you to your Lord so you would fear [Him]?''"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he showed him the greatest sign,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But Pharaoh denied and disobeyed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then he turned his back, striving.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he gathered [his people] and called out', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And said, "I am your most exalted lord."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So Allah seized him in exemplary punishment for the last and the first [transgression].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed in that is a warning for whoever would fear [Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Are you a more difficult creation or is the heaven? Allah constructed it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He raised its ceiling and proportioned it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He darkened its night and extracted its brightness.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And after that He spread the earth.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He extracted from it its water and its pasture,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the mountains He set firmly', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As provision for you and your grazing livestock.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when there comes the greatest Overwhelming Calamity -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Day when man will remember that for which he strove,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Hellfire will be exposed for [all] those who see -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So as for he who transgressed', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And preferred the life of the world,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then indeed, Hellfire will be [his] refuge.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for he who feared the position of his Lord and prevented the soul from [unlawful] inclination,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then indeed, Paradise will be [his] refuge.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They ask you, [O Muhammad], about the Hour: when is its arrival?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'In what [position] are you that you should mention it?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To your Lord is its finality.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You are only a warner for those who fear it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 79 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It will be, on the Day they see it, as though they had not remained [in the world] except for an afternoon or a morning thereof.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Prophet frowned and turned away', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Because there came to him the blind man, [interrupting].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But what would make you perceive, [O Muhammad], that perhaps he might be purified', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or be reminded and the remembrance would benefit him?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As for he who thinks himself without need,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To him you give attention.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And not upon you [is any blame] if he will not be purified.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for he who came to you striving [for knowledge]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'While he fears [Allah],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'From him you are distracted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! Indeed, these verses are a reminder;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So whoever wills may remember it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It is recorded] in honored sheets,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Exalted and purified,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Carried] by the hands of messenger-angels,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Noble and dutiful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Cursed is man; how disbelieving is he.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'From what substance did He create him?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'From a sperm-drop He created him and destined for him;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then He eased the way for him;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then He causes his death and provides a grave for him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then when He wills, He will resurrect him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! Man has not yet accomplished what He commanded him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then let mankind look at his food -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'How We poured down water in torrents,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We broke open the earth, splitting [it with sprouts],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And caused to grow within it grain', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And grapes and herbage', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And olive and palm trees', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And gardens of dense shrubbery', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And fruit and grass -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[As] enjoyment for you and your grazing livestock.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when there comes the Deafening Blast', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On the Day a man will flee from his brother', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And his mother and his father', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And his wife and his children,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For every man, that Day, will be a matter adequate for him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Some] faces, that Day, will be bright -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Laughing, rejoicing at good news.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [other] faces, that Day, will have upon them dust.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Blackness will cover them.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 80 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those are the disbelievers, the wicked ones.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When the sun is wrapped up [in darkness]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the stars fall, dispersing,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the mountains are removed', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when full-term she-camels are neglected', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the wild beasts are gathered', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the seas are filled with flame', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the souls are paired', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the girl [who was] buried alive is asked', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For what sin she was killed', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the pages are made public', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the sky is stripped away', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when Hellfire is set ablaze', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when Paradise is brought near,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A soul will [then] know what it has brought [with it].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So I swear by the retreating stars -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those that run [their courses] and disappear -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And by the night as it closes in', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And by the dawn when it breathes', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[That] indeed, the Qur''an is a word [conveyed by] a noble messenger', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Who is] possessed of power and with the Owner of the Throne, secure [in position],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Obeyed there [in the heavens] and trustworthy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And your companion is not [at all] mad.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he has already seen Gabriel in the clear horizon.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Muhammad is not a withholder of [knowledge of] the unseen.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the Qur''an is not the word of a devil, expelled [from the heavens].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So where are you going?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is not except a reminder to the worlds', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For whoever wills among you to take a right course.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 81 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you do not will except that Allah wills - Lord of the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When the sky breaks apart', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the stars fall, scattering,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the seas are erupted', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the [contents of] graves are scattered,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A soul will [then] know what it has put forth and kept back.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O mankind, what has deceived you concerning your Lord, the Generous,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who created you, proportioned you, and balanced you?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'In whatever form He willed has He assembled you.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! But you deny the Recompense.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, [appointed] over you are keepers,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Noble and recording;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They know whatever you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the righteous will be in pleasure,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, the wicked will be in Hellfire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will [enter to] burn therein on the Day of Recompense,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And never therefrom will they be absent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what can make you know what is the Day of Recompense?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then, what can make you know what is the Day of Recompense?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 82 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is the Day when a soul will not possess for another soul [power to do] a thing; and the command, that Day, is [entirely] with Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Woe to those who give less [than due],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who, when they take a measure from people, take in full.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if they give by measure or by weight to them, they cause loss.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do they not think that they will be resurrected', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For a tremendous Day -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Day when mankind will stand before the Lord of the worlds?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! Indeed, the record of the wicked is in sijjeen.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what can make you know what is sijjeen?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is [their destination recorded in] a register inscribed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Woe, that Day, to the deniers,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who deny the Day of Recompense.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And none deny it except every sinful transgressor.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When Our verses are recited to him, he says, "Legends of the former peoples."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! Rather, the stain has covered their hearts of that which they were earning.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! Indeed, from their Lord, that Day, they will be partitioned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then indeed, they will [enter and] burn in Hellfire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then it will be said [to them], "This is what you used to deny."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! Indeed, the record of the righteous is in ''illiyyun.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what can make you know what is ''illiyyun?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is [their destination recorded in] a register inscribed', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Which is witnessed by those brought near [to Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the righteous will be in pleasure', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On adorned couches, observing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You will recognize in their faces the radiance of pleasure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will be given to drink [pure] wine [which was] sealed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The last of it is musk. So for this let the competitors compete.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And its mixture is of Tasneem,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A spring from which those near [to Allah] drink.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who committed crimes used to laugh at those who believed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they passed by them, they would exchange derisive glances.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they returned to their people, they would return jesting.', NOW(), NOW()),
