((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they had not been sent as guardians over them.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So Today those who believed are laughing at the disbelievers,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On adorned couches, observing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 83 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have the disbelievers [not] been rewarded [this Day] for what they used to do?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When the sky has split [open]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And has responded to its Lord and was obligated [to do so]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the earth has been extended', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And has cast out that within it and relinquished [it]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And has responded to its Lord and was obligated [to do so] -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O mankind, indeed you are laboring toward your Lord with [great] exertion and will meet it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then as for he who is given his record in his right hand,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He will be judged with an easy account', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And return to his people in happiness.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for he who is given his record behind his back,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He will cry out for destruction', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [enter to] burn in a Blaze.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, he had [once] been among his people in happiness;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, he had thought he would never return [to Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But yes! Indeed, his Lord was ever of him, Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So I swear by the twilight glow', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the night and what it envelops', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the moon when it becomes full', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[That] you will surely experience state after state.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So what is [the matter] with them [that] they do not believe,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the Qur''an is recited to them, they do not prostrate [to Allah]?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But those who have disbelieved deny,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah is most knowing of what they keep within themselves.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 84 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So give them tidings of a painful punishment,', NOW(), NOW()),
