((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] ten nights', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the even [number] and the odd', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the night when it passes,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is there [not] in [all] that an oath [sufficient] for one of perception?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you not considered how your Lord dealt with ''Aad -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[With] Iram - who had lofty pillars,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The likes of whom had never been created in the land?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [with] Thamud, who carved out the rocks in the valley?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [with] Pharaoh, owner of the stakes? -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[All of] whom oppressed within the lands', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And increased therein the corruption.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So your Lord poured upon them a scourge of punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, your Lord is in observation.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And as for man, when his Lord tries him and [thus] is generous to him and favors him, he says, "My Lord has honored me."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when He tries him and restricts his provision, he says, "My Lord has humiliated me."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! But you do not honor the orphan', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you do not encourage one another to feed the poor.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you consume inheritance, devouring [it] altogether,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you love wealth with immense love.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! When the earth has been leveled - pounded and crushed -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And your Lord has come and the angels, rank upon rank,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And brought [within view], that Day, is Hell - that Day, man will remember, but what good to him will be the remembrance?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He will say, "Oh, I wish I had sent ahead [some good] for my life."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So on that Day, none will punish [as severely] as His punishment,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And none will bind [as severely] as His binding [of the evildoers].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[To the righteous it will be said], "O reassured soul,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Return to your Lord, well-pleased and pleasing [to Him],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And enter among My [righteous] servants', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 89 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And enter My Paradise."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'I swear by this city, Makkah -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you, [O Muhammad], are free of restriction in this city -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the father and that which was born [of him],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We have certainly created man into hardship.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Does he think that never will anyone overcome him?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He says, "I have spent wealth in abundance."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Does he think that no one has seen him?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have We not made for him two eyes?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And a tongue and two lips?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And have shown him the two ways?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But he has not broken through the difficult pass.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what can make you know what is [breaking through] the difficult pass?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is the freeing of a slave', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or feeding on a day of severe hunger', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'An orphan of near relationship', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or a needy person in misery', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And then being among those who believed and advised one another to patience and advised one another to compassion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those are the companions of the right.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they who disbelieved in Our signs - those are the companions of the left.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 90 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Over them will be fire closed in.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By the sun and its brightness', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the moon when it follows it', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the day when it displays it', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the night when it covers it', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the sky and He who constructed it', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the earth and He who spread it', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the soul and He who proportioned it', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And inspired it [with discernment of] its wickedness and its righteousness,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He has succeeded who purifies it,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he has failed who instills it [with corruption].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Thamud denied [their prophet] by reason of their transgression,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When the most wretched of them was sent forth.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the messenger of Allah [Salih] said to them, "[Do not harm] the she-camel of Allah or [prevent her from] her drink."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they denied him and hamstrung her. So their Lord brought down upon them destruction for their sin and made it equal [upon all of them].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 91 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He does not fear the consequence thereof.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By the night when it covers', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the day when it appears', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] He who created the male and female,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, your efforts are diverse.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As for he who gives and fears Allah', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And believes in the best [reward],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We will ease him toward ease.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for he who withholds and considers himself free of need', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And denies the best [reward],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We will ease him toward difficulty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what will his wealth avail him when he falls?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, [incumbent] upon Us is guidance.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, to Us belongs the Hereafter and the first [life].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So I have warned you of a Fire which is blazing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'None will [enter to] burn therein except the most wretched one.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who had denied and turned away.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But the righteous one will avoid it -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[He] who gives [from] his wealth to purify himself', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And not [giving] for anyone who has [done him] a favor to be rewarded', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But only seeking the countenance of his Lord, Most High.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 92 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he is going to be satisfied.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 93 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By the morning brightness', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 93 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] the night when it covers with darkness,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 93 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Your Lord has not taken leave of you, [O Muhammad], nor has He detested [you].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 93 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the Hereafter is better for you than the first [life].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 93 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And your Lord is going to give you, and you will be satisfied.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 93 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Did He not find you an orphan and give [you] refuge?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 93 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He found you lost and guided [you],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 93 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He found you poor and made [you] self-sufficient.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 93 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So as for the orphan, do not oppress [him].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 93 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And as for the petitioner, do not repel [him].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 93 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for the favor of your Lord, report [it].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 94 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Did We not expand for you, [O Muhammad], your breast?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 94 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We removed from you your burden', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 94 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Which had weighed upon your back', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 94 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And raised high for you your repute.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 94 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For indeed, with hardship [will be] ease.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 94 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, with hardship [will be] ease.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 94 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when you have finished [your duties], then stand up [for worship].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 94 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to your Lord direct [your] longing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 95 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By the fig and the olive', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 95 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] Mount Sinai', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 95 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [by] this secure city [Makkah],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 95 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We have certainly created man in the best of stature;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 95 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We return him to the lowest of the low,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 95 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except for those who believe and do righteous deeds, for they will have a reward uninterrupted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 95 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So what yet causes you to deny the Recompense?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 95 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is not Allah the most just of judges?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Recite in the name of your Lord who created -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Created man from a clinging substance.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Recite, and your Lord is the most Generous -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who taught by the pen -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Taught man that which he knew not.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! [But] indeed, man transgresses', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Because he sees himself self-sufficient.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, to your Lord is the return.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you seen the one who forbids', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A servant when he prays?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you seen if he is upon guidance', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or enjoins righteousness?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you seen if he denies and turns away -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Does he not know that Allah sees?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! If he does not desist, We will surely drag him by the forelock -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A lying, sinning forelock.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then let him call his associates;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We will call the angels of Hell.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 96 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! Do not obey him. But prostrate and draw near [to Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 97 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We sent the Qur''an down during the Night of Decree.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 97 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what can make you know what is the Night of Decree?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 97 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Night of Decree is better than a thousand months.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 97 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The angels and the Spirit descend therein by permission of their Lord for every matter.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 97 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Peace it is until the emergence of dawn.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 98 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who disbelieved among the People of the Scripture and the polytheists were not to be parted [from misbelief] until there came to them clear evidence -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 98 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A Messenger from Allah, reciting purified scriptures', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 98 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Within which are correct writings.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 98 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nor did those who were given the Scripture become divided until after there had come to them clear evidence.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 98 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they were not commanded except to worship Allah, [being] sincere to Him in religion, inclining to truth, and to establish prayer and to give zakah. And that is the correct religion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 98 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, they who disbelieved among the People of the Scripture and the polytheists will be in the fire of Hell, abiding eternally therein. Those are the worst of creatures.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 98 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, they who have believed and done righteous deeds - those are the best of creatures.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 98 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Their reward with Allah will be gardens of perpetual residence beneath which rivers flow, wherein they will abide forever, Allah being pleased with them and they with Him. That is for whoever has feared his Lord.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 99 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When the earth is shaken with its [final] earthquake', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 99 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the earth discharges its burdens', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 99 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And man says, "What is [wrong] with it?" -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 99 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That Day, it will report its news', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 99 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Because your Lord has commanded it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 99 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That Day, the people will depart separated [into categories] to be shown [the result of] their deeds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 99 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So whoever does an atom''s weight of good will see it,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 99 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whoever does an atom''s weight of evil will see it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 100 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By the racers, panting,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 100 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the producers of sparks [when] striking', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 100 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the chargers at dawn,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 100 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Stirring up thereby [clouds of] dust,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 100 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Arriving thereby in the center collectively,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 100 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed mankind, to his Lord, is ungrateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 100 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, he is to that a witness.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 100 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed he is, in love of wealth, intense.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 100 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But does he not know that when the contents of the graves are scattered', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 100 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And that within the breasts is obtained,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 100 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, their Lord with them, that Day, is [fully] Acquainted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 101 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Striking Calamity -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 101 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'What is the Striking Calamity?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 101 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what can make you know what is the Striking Calamity?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 101 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is the Day when people will be like moths, dispersed,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 101 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the mountains will be like wool, fluffed up.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 101 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then as for one whose scales are heavy [with good deeds],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 101 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He will be in a pleasant life.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 101 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for one whose scales are light,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 101 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'His refuge will be an abyss.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 101 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what can make you know what that is?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 101 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is a Fire, intensely hot.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 102 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Competition in [worldly] increase diverts you', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 102 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Until you visit the graveyards.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 102 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! You are going to know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 102 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then no! You are going to know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 102 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! If you only knew with knowledge of certainty...', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 102 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You will surely see the Hellfire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 102 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then you will surely see it with the eye of certainty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 102 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then you will surely be asked that Day about pleasure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 103 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By time,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 103 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, mankind is in loss,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 103 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except for those who have believed and done righteous deeds and advised each other to truth and advised each other to patience.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 104 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Woe to every scorner and mocker', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 104 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who collects wealth and [continuously] counts it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 104 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He thinks that his wealth will make him immortal.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 104 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No! He will surely be thrown into the Crusher.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 104 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what can make you know what is the Crusher?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 104 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is the fire of Allah, [eternally] fueled,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 104 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Which mounts directed at the hearts.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 104 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Hellfire will be closed down upon them', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 104 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'In extended columns.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 105 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you not considered, [O Muhammad], how your Lord dealt with the companions of the elephant?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 105 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Did He not make their plan into misguidance?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 105 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He sent against them birds in flocks,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 105 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Striking them with stones of hard clay,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 105 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He made them like eaten straw.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 106 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For the accustomed security of the Quraysh -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 106 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Their accustomed security [in] the caravan of winter and summer -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 106 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Let them worship the Lord of this House,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 106 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who has fed them, [saving them] from hunger and made them safe, [saving them] from fear.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 107 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you seen the one who denies the Recompense?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 107 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For that is the one who drives away the orphan', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 107 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And does not encourage the feeding of the poor.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 107 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So woe to those who pray', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 107 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[But] who are heedless of their prayer -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 107 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who make show [of their deeds]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 107 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And withhold [simple] assistance.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 108 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have granted you, [O Muhammad], al-Kawthar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 108 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So pray to your Lord and sacrifice [to Him alone].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 108 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, your enemy is the one cut off.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 109 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "O disbelievers,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 109 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'I do not worship what you worship.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 109 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nor are you worshippers of what I worship.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 109 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nor will I be a worshipper of what you worship.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 109 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nor will you be worshippers of what I worship.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 109 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For you is your religion, and for me is my religion."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 110 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When the victory of Allah has come and the conquest,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 110 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you see the people entering into the religion of Allah in multitudes,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 110 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then exalt [Him] with praise of your Lord and ask forgiveness of Him. Indeed, He is ever Accepting of repentance.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 111 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'May the hands of Abu Lahab be ruined, and ruined is he.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 111 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'His wealth will not avail him or that which he gained.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 111 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He will [enter to] burn in a Fire of [blazing] flame', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 111 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And his wife [as well] - the carrier of firewood.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 111 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Around her neck is a rope of [twisted] fiber.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 112 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "He is Allah, [who is] One,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 112 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah, the Eternal Refuge.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 112 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He neither begets nor is born,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 112 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nor is there to Him any equivalent."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 113 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "I seek refuge in the Lord of daybreak', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 113 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'From the evil of that which He created', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 113 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And from the evil of darkness when it settles', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 113 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And from the evil of the blowers in knots', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 113 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And from the evil of an envier when he envies."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 114 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "I seek refuge in the Lord of mankind,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 114 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Sovereign of mankind.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 114 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The God of mankind,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 114 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'From the evil of the retreating whisperer -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 114 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who whispers [evil] into the breasts of mankind -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 114 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'From among the jinn and mankind."', NOW(), NOW());
